import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        int bufferSize = Math.min(name.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copying only up to the buffer size
        name.getChars(0, bufferSize, buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
